var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"경비부대, 전원 집합했습니다.","JPN":"総員、集結しました。","ENG":"All of us guards are here.","TWN":"守衛部隊集合完畢。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"그리고 지시하셨던 대로 감시 카메라를 확인해 보았습니다.","JPN":"それから、ご指示どおり、監視カメラを確認してみました。","ENG":"And we've checked the surveillance cameras as you asked.","TWN":"按照您的指示，確認了監視器。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"믿기 어렵지만...... 침입자들은 반응로 근처에서 갑자기 나타난 것 같습니다.","JPN":"信じがたいですが……侵入者は反応炉の近くから突如現れたようです。","ENG":"This is hard to believe, but the intruders suddenly appeared near the reactor.","TWN":"雖然難以置信……但入侵者們好像是突然出現在反應爐周圍的。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다면......","JPN":"それなら……","ENG":"Then...","TWN":"這樣說來……"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"역시 폭주한 반응로에서 방출된 에너지를 매개로 차원계면을 뚫고 나온 것 같군요.","JPN":"やはり暴走中の反応炉から放たれたエネルギーを媒介にして、次元界面を突破したようですね。","ENG":"They really must have come through the dimension surface because of the energy released from the overloaded reactor.","TWN":"果然是反應爐暴走後，釋放出的能量成為媒介，突破了次元邊界。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"하지만 소령님, 이면세계를 떠돌다가 온 것 치고는 몸도 정신도 멀쩡해 보였습니다.","JPN":"ですが少佐、裏世界をさまよっていたわりには、肉体も精神もまともに見えました。","ENG":"But Major, they didn't look like they'd wandered about the Counterside. They looked too normal for that.","TWN":"但是少校，如果她們是從異界過來的，精神和肉體似乎都過於正常。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"타당한 지적입니다. 그런 의문점들은 체포 후 심문 과정을 통해 알아낼 수 있을 겁니다.","JPN":"妥当な指摘です。そのような疑問は逮捕した後、尋問すれば突き止められるかと。","ENG":"I agree. We'll get answers to those questions once we capture them.","TWN":"你說的沒錯。這些疑問，你可以逮捕後親自問她們。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그보다 지원군 요청은 어떻게 됐습니까?","JPN":"それより、援軍要請の進捗はいかがですか？","ENG":"By the way, how goes the request for reinforcements?","TWN":"比起這個，我們請求增援的狀況怎麼樣了？"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"몇 차례 시도했지만 모두 실패로 돌아갔습니다.","JPN":"何度も試しましたが、すべて失敗におわりました。","ENG":"I've tried several times, but to no avail.","TWN":"我試了幾次，但全部都失敗了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"아마도 반응로 폭주의 영향으로 장거리 통신이 방해 받고 있는 것 같습니다.","JPN":"おそらく反応炉の暴走により、長距離通信が正常に行えないようです。","ENG":"It seems the rampaging energy from the reactor is interrupting long-distance communication.","TWN":"似乎是受到爆炸的影響，遠端通訊遭到了干擾。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 더 이상의 연락 시도는 의미가 없겠군요.","JPN":"それならば、これ以上連絡しても意味がないでしょうね。","ENG":"Then, there's no use trying to use it.","TWN":"那就沒必要再嘗試了。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"일단 별동대를 편성해서 가장 가까운 기지로 보내세요. 시급히 상황을 전해야 합니다.","JPN":"まずは別動隊を編成して、最も近場の基地に派遣してください。至急この状況を伝えねば。","ENG":"Please send out a detached force to the nearest base. We must alert it of our situation.","TWN":"組織一個分隊派到最近的基地去，必須要立刻將這個緊急狀況上報。"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"예, 소령님!","JPN":"はい、少佐！","ENG":"Yes, Major.","TWN":"是，少校！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"별동대를 제외한 전 병력은 현 시간부로 침입자를 찾기 위한 긴급 수색작전을 개시합니다!","JPN":"別動隊を除く全兵力は、これより侵入者を捜すための緊急捜索作戦を開始します！","ENG":"Everyone, except for the detached force, will start looking for the intruders.","TWN":"除了分隊以外，所有部隊現在開始進行緊急搜索作戰，找出入侵者！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기밀 사항이 유출될 위험이 있는 만큼, 다들 서둘러 주십시오!","JPN":"機密漏えいの恐れがありますので、皆さん、急いでください！","ENG":"Let's hurry. Our classified information is at stake.","TWN":"因為有機密情報洩露的危險，請各位盡速行動！"},"stage":{"bg":"HANGAR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이야, 잠깐 쉬는 동안 사람이 쫙 깔렸네요. 이래서야 한 발자국도 못 움직이겠어요.","JPN":"うひゃ～、一息ついてたらものすごい人数が集まりましたね。これじゃ、一歩も動けそうにありません。","ENG":"Wow, so many people came to look for us for the short time we took a break. We can't go anywhere now.","TWN":"哎呀，才休息一會兒就聚集了這麼多人。這樣我們連一步都動不了啊。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"충돌은 피할 수 없겠군요.","JPN":"衝突は避けられませんね。","ENG":"A clash is inevitable.","TWN":"無法避免衝突了呢。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"방침을 바꿔야겠습니다. 우리가 처음 도착했던 장소로 돌아가죠.","JPN":"方針を変えましょう。私たちが最初着いたところに引き返します。","ENG":"Change of plans. Let's go back to the first place we were.","TWN":"看來得改變方針了。我們回到一開始到達的地方吧。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네이, 네이......","JPN":"はいはい……","ENG":"Sure, sure...","TWN":"是，是……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네이?","JPN":"って、まさか？","ENG":"What?","TWN":"是？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저기, 카린 양? 자신감이 넘치는 건 좋지만, 저 병력에 우리 둘이 달려드는 건 좀 무리가 아닐까요?","JPN":"あのぉ、カリンさん？　\\n自信満々なのは結構なことですが、二人っきりであの兵力に立ち向かうのは無理なのでは？","ENG":"Err, Karin? I like your confidence, but it may be too ambitious to take on so many people just between the two of us.","TWN":"那個，卡琳小姐？有自信是很好，但面對這樣的兵力，只有我們兩個人會不會太勉強了？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"프로페셔널한 용병이라면서요. 그럼 의뢰주의 요구에 부응하세요.","JPN":"プロフェッショナルな傭兵なのでしょう？　だったら、依頼人の要求に応じてください。","ENG":"You said you're a professional mercenary. You'd better meet your client's demands.","TWN":"妳是個職業傭兵，那就請完成委託人的要求。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아...... 역시 박봉이라도 평범한 직장을 찾았어야 하나?","JPN":"はあ……やっぱり薄給でも普通の職場を探すべきだったかな？","ENG":"*Sigh...* Maybe I should've gotten an ordinary job, even if it didn't pay well...","TWN":"唉……就算錢比較少，但我還是該去找個普通工作嗎？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"소령님! 침입자들이 실험시설로 향하고 있습니다! 대응하겠습니다!","JPN":"少佐！　侵入者たちが実験施設に向かっています！　対応します！","ENG":"Major, the intruders are heading for our testing facility. We'll stop them!","TWN":"少校！入侵者正往實驗設施方向前進！讓我來對付她們！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저도 추격 중입니다! 접근하게 두면 위험하니 거리를 유지하면서 엄호하세요!","JPN":"僕も追いかけているところです！　近づくのは危険なので、一定距離をキープしながら援護してください！","ENG":"I'm on my way, too. We can't let them get close. Cover me from a distance!","TWN":"我也正在追擊！貿然接近會有危險，記得保持距離互相掩護！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"큭, 하필 이럴 때 워커 대령님이 부재 중이라니......","JPN":"くっ、こんなときに限って、ウォーカー大佐が不在だなんて……","ENG":"Gah, Colonel Walker is away just when I need him!","TWN":"該死，偏偏這種時候沃克上校不在……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양! 제가 근무 환경에 불만이 많은 편은 아니라고 생각하는데, 지금은 살짝 문제가 느껴지네요!","JPN":"カリンさん！　私って、勤務環境にうるさいほうじゃないと思いますけど、今の状況はちょっと問題ありかと！","ENG":"Karin, I usually don't complain a lot about my working conditions, but I feel that now's the time I should.","TWN":"卡琳小姐！我自認為不是那種對工作環境有很多不滿的人，但我現在好像發現一些小問題！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"조금 전부터 카린 양의 이세계 오빠로 추정되는 분께서 제 가녀린 몸을 향해 무자비하게 탄환을 쏟아 붓고 계시거든요?","JPN":"裏世界版のカリンさんのお兄さんっぽい方が、さっきから私の華奢な体に弾丸を浴びせていますよ？","ENG":"The person who's suspected to be your otherworldly brother is firing a barrage of bullets at me.","TWN":"就在不久前，據說是卡琳小姐的異世界哥哥正無情地把子彈灌到我嬌弱的身體上耶？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데 카린 양은 대체 거기서 혼자 뭘 하고 계신 거죠?","JPN":"って、カリンさんはそこでいったい何をしてるんです？","ENG":"And what are you doing over there alone?","TWN":"話說回來，卡琳小姐妳一個人在那裡搞什麼鬼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 아무리 최강의 프리랜서 용병이자 천재 검사라지만 이런 상황에선 후방 지원이라는 게 필요하다고요!","JPN":"いくら私が最強のフリー傭兵兼天才剣士だとしても、こんな状況では後方支援が欠かせませんよ！","ENG":"I may be the world's greatest freelancing mercenary and genius swordswoman, but even I need support in a situation like this!","TWN":"就算我是最強的職業傭兵兼天才劍士，在這種情況下，還是需要後方支援的好嗎！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"미안하지만 조금만 혼자 더 버텨 주세요!","JPN":"悪いけど、もう少しだけ一人で耐えてください！","ENG":"I'm sorry, but hold out on your own for a little longer!","TWN":"不好意思，請妳再撐一下！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"여기에 있는 이 시설들......","JPN":"ここの施設……","ENG":"These facilities here...","TWN":"這裡的設施……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이건 우리 세계와 비교도 안 되게 진보한 이터니움 공학 기술로 만들어진 것들입니다.","JPN":"これは私たちの世界とは比べ物にならないほど進歩したエタニウム工学技術によって建てられたものです。","ENG":"They're built with an Eternium engineering technology that's advanced beyond our world's.","TWN":"是用我們世界完全無法比擬的高度永恆之金工學技術建造的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 시설의 정보를 알아낸다면, 우리 임무의 성공률을 획기적으로 높일 수 있을 거에요.","JPN":"この施設の情報を調べたら、私たちの任務の成功率を画期的に引き上げられると思います。","ENG":"If I can get some information, it'll remarkably improve the results of our mission.","TWN":"如果能調查出這個設施的情報，就能大大提高我們任務的成功率。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......그러니까 안 도와준다는 말을 굉장히 어렵게 돌려서 말하시네요.","JPN":"……つまりは、手伝う気はないということをすごく遠回しに言ってるんですね。","ENG":"In other words, you're not going to help me.","TWN":"……所以要妳直接說妳不想幫忙是一件很難的事情就對了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하긴 뭐 총알받이 신세가 어제오늘 일도 아니죠.","JPN":"まあ、人間の盾役は慣れっこですけどね。","ENG":"Well, this is not the first time that I've been left to fend for myself.","TWN":"算了，我當槍靶子也不是一兩天的事了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"내가 진짜 억울해서 칼 버리고 사격술을 배우던가 해야지 원.","JPN":"いっそのこと、刀なんか捨てて、銃でも持とうかな。","ENG":"Geez, do I really need to give up my sword and learn how to shoot a gun?","TWN":"我真的很後悔，早知道我就該把劍扔掉，去學射擊了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"소령님! 적이 엄폐물에서 나와 접근 중입니다!","JPN":"少佐！　侵入者がシェルターから出て、近づいてきています！","ENG":"Major, the enemy is approaching us!","TWN":"少校！敵人離開了掩體，正在接近！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"빠릅니다! 조준 사격 불가능! 저지선 돌파!","JPN":"速い！　照準射撃できません！　阻止線を突破！","ENG":"Too fast! She's already broken through the lines!","TWN":"速度非常快！無法瞄準射擊！已突破防線！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"접근하는 적은 제가 상대합니다! 전열을 무너트리지 마십시오!","JPN":"近づいてくる敵は僕が相手します！　戦列を崩さないように！","ENG":"I'll deal with her! Stay where you are!","TWN":"我來對付接近的敵人！不要亂了陣腳！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"큭......?!","JPN":"くっ……！？","ENG":"Ugh!","TWN":"唔……？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와우, 가까이서 보니까 정말 닮았네요.","JPN":"おお、近くでみたら、ますます瓜二つだこと。","ENG":"Wow! Up close, you really look like her.","TWN":"嗚哇，近距離一看真的很像耶。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시 이름도 얼굴만큼 비슷하려나.","JPN":"ひょっとして名前も似てたりして。","ENG":"I wonder if your name is also similar to hers.","TWN":"說不定名字也和臉一樣呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"무슨 말인지 모르겠지만 끝까지 저항할 생각이라면 쉽지는 않을 겁니다!","JPN":"おっしゃっている意味がわかりませんが、最後まで抵抗するつもりならそう簡単にはいきませんよ！","ENG":"I don't know what you're talking about, but you'd better stop resisting soon!","TWN":"雖然不知道妳在說什麼，但妳如果要抵抗到底，可沒有那麼容易！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"말씀도 귀여우셔라. 왠지 괴롭히고 싶어지는 타입인 걸요?","JPN":"まあ、可愛いことをおっしゃる。何だかイタズラしたくなるタイプ？","ENG":"You even sound cute. You make me want to pester you.","TWN":"說的話也很可愛啊。總覺得你是那種我會想欺負的類型喔？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 최대한 안 아프게 찔러드릴 테니까 힘 빼시는 게 좋아요.","JPN":"さあ、極力痛くないように刺してあげますから、力を抜いたほうが賢明ですよ。","ENG":"Okay, I'll stab you as gently as possible. Now, loosen up.","TWN":"來吧，我針筒會儘可能地打輕一點，你放鬆一點會比較好喔。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};